instruction:
Declare a variable with its type and name:

```csharp
int age = 25;
string name = "Alice";
```

Run this.

starter:
using System;

class Program {
    static void Main() {
        int age = 25;
        string name = "Alice";
        Console.WriteLine($"{name} is {age}");
    }
}

using System;

class Program {
    static void Main() {
        var x = 42;      // int
        var pi = 3.14;   // double
        var msg = "hi"; // string
        Console.WriteLine($"{x} {pi} {msg}");
    }
}

using System;

class Program {
    static void Main() {
        int score = 0;
        Console.WriteLine($"start: {score}");
        score = 50;
        Console.WriteLine($"after: {score}");
        score += 25;
        Console.WriteLine($"final: {score}");
    }
}

using System;

class Program {
    const double Pi = 3.14159;
    const int MaxScore = 100;

    static void Main() {
        Console.WriteLine($"Pi = {Pi}");
        Console.WriteLine($"Max score = {MaxScore}");
    }
}

